INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('8c5b60e1-399c-4e5d-abb8-d981920fa47d', 'Vật lý trị liệu cho bệnh nhân thoái hóa khớp gối: Giảm đau không dùng thuốc', 'vat-ly-tri-lieu-thoai-hoa-khop-goi', 'Thoái hóa khớp gối gây đau nhức ê ẩm mỗi khi đứng lên ngồi xuống hay lên xuống cầu thang. Vật lý trị liệu phục hồi chức năng giúp làm chậm đáng kể tốc độ bào mòn sụn khớp.', '<img src="/uploads/blog/2221a372-82fd-4698-9a82-56b8a4dacb30.webp" /><h2>1. Cơ chế tiến triển của thoái hóa khớp gối</h2><p>Khớp gối bị thoái hóa khi lớp sụn bảo vệ bọc đầu xương đùi và xương chày bị bào mòn, mỏng dần theo thời gian. Sự mất đi của đệm giảm chấn tự nhiên khiến hai đầu xương trực tiếp cọ xát vào nhau khi vận động, tạo ra những âm thanh lắc rắc và gây đau buốt dữ dội.</p><h2>2. Mục tiêu điều trị bằng Vật lý trị liệu</h2><p>Phục hồi chức năng khớp gối hướng tới 3 mục tiêu cốt lõi:</p><ul><li><p><strong>Tăng cường sức mạnh cơ đùi (Cơ tứ đầu đùi):</strong> Cơ đùi khỏe mạnh sẽ đóng vai trò như một bộ phuộc giảm chấn, gánh bớt 50% tải trọng truyền xuống khớp gối.</p></li><li><p><strong>Kích thích tiết dịch khớp tự nhiên:</strong> Các bài tập vận động thụ động và chủ động nhẹ nhàng hỗ trợ bao hoạt dịch tăng tiết dịch nhầy bôi trơn khớp gối.</p></li></ul><h2>3. Các bài tập khớp gối an toàn tại PhysioFlow</h2><p>Bệnh nhân được thiết kế tập đạp xe tại chỗ không lực cản, bài tập nhấc thẳng chân khi nằm ngửa, và bài tập kéo giãn cơ bắp chuối sau bắp chân.</p>', '/Baiviet/images/dau_khop_goi.png', 'dieu_tri', 'xuat_ban', 'Vật lý trị liệu thoái hóa khớp gối không dùng thuốc', 'Liệu pháp phục hồi chức năng khớp gối giúp giảm đau, tăng tiết dịch khớp tự nhiên.', 'thoai hoa khop goi, dau goi, dich khop goi, vat ly tri lieu goi', 537, 5, '2026-07-19T11:47:18.701Z', '2026-07-17T05:21:29.598Z', '2026-07-19T11:47:18.702Z');
INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('eb0ad960-77be-4ca4-833b-0d02a5deacaf', 'Phục hồi chức năng thoái hóa cột sống thắt lưng bằng phương pháp tiên tiến', 'phuc-hoi-chuc-nang-thoai-hoa-cot-song-that-lung', 'Thoái hóa cột sống thắt lưng là căn bệnh mãn tính phổ biến gây đau nhức và hạn chế vận động nghiêm trọng. Khám phá các giải pháp phục hồi chức năng tiên tiến không phẫu thuật giúp tái tạo đĩa đệm và phục hồi biên độ vận động hiệu quả.', '<h2>1. Hiểu đúng về bệnh lý thoái hóa cột sống thắt lưng</h2>
INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('101a74c7-2da9-486e-9b9a-8d136f301127', 'Liệu pháp sóng xung kích (Shockwave Therapy) trong điều trị gai gót chân', 'lieu-phap-song-xung-kich-dieu-tri-gai-got-chan', 'Đau gót chân do viêm cân gan chân hay gai gót chân gây cản trở sinh hoạt trầm trọng. Liệu pháp sóng xung kích (Shockwave) được đánh giá là tiêu chuẩn vàng giúp cắt đứt cơn đau chỉ sau vài liệu trình.', '<h2>1. Hội chứng gai gót chân và viêm cân gan chân là gì?</h2>
INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('baeaf52c-bb70-407e-bbe5-c3662120a60e', 'Điều trị thoát vị đĩa đệm không phẫu thuật: Hiệu quả thực tế ra sao?', 'dieu-tri-thoat-vi-dia-dem-khong-phau-thuat', 'Nhiều người lo sợ phải phẫu thuật khi phát hiện thoát vị đĩa đệm. Y học hiện đại chứng minh đến 95% trường hợp thoát vị đĩa đệm có thể điều trị thành công bằng các biện pháp bảo tồn và phục hồi chức năng.', '<h2>1. Hiểu đúng về thoát vị đĩa đệm</h2>
INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('c4928a6b-90d5-44e8-8467-d732358ace6a', 'Laser công suất cao (Class IV): Công nghệ đột phá giảm viêm đau nhanh', 'laser-cong-suat-cao-cong-nghe-giam-dau-nhanh', 'Công nghệ trị liệu Laser công suất cao Class IV mang lại khả năng thâm nhập sâu vào các mô cơ khớp tổn thương, mang lại tác dụng kháng viêm và cắt đứt cơn đau nhanh tức thì.', '<h2>1. Laser công suất cao Class IV là gì?</h2>
INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('ca84c243-a026-4bc6-9c9c-06097bfeb146', 'Tầm quan trọng của lượng giá chức năng cơ xương khớp trước khi trị liệu', 'tam-quan-trong-luong-gia-co-xuong-khop', 'Trị liệu cơ xương khớp không thể thành công nếu thiếu bước lượng giá chức năng ban đầu. Đây là chìa khóa để chẩn đoán đúng gốc rễ cơn đau và thiết kế phác đồ cá nhân hóa tối ưu.', '<h2>1. Lượng giá chức năng cơ xương khớp là gì?</h2>
INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('63bb80ff-d9af-4188-9df2-c569150f909b', 'Giải cơ sâu Myofascial Release: Giải pháp cho các điểm đau kích hoạt (Trigger Points)', 'giai-co-sau-myofascial-release', 'Các điểm đau kích hoạt (nút thắt cơ) gây ra những cơn đau ê ẩm lan tỏa toàn thân. Liệu pháp giải cơ sâu Myofascial Release giúp giải phóng căng thẳng màng cơ hiệu quả.', '<h2>1. Điểm đau kích hoạt (Trigger Points) là gì?</h2>
INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('0b078f6a-bebe-40fc-87f4-de4f81ebc4ea', 'Điều trị viêm quanh khớp vai bằng phương pháp phục hồi chức năng', 'dieu-tri-viem-quanh-khop-vai', 'Viêm quanh khớp vai hay đông cứng khớp vai khiến bệnh nhân đau đớn dữ dội khi nhấc tay, chải đầu hay mặc áo. Khám phá phác đồ phục hồi chức năng lấy lại sự linh hoạt cho khớp vai.', '<h2>1. Nhận biết bệnh lý viêm quanh khớp vai</h2>
INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('1664912b-8975-4655-9167-f1d10f0f76c8', 'Phục hồi đứt dây chằng chéo trước (ACL) sau phẫu thuật tái tạo', 'phuc-hoi-dut-day-chang-cheo-truoc-acl', 'Tái tạo dây chằng chéo trước (ACL) bằng nội soi chỉ mới quyết định 50% sự thành công. 50% còn lại phụ thuộc hoàn toàn vào lộ trình tập phục hồi chức năng sau mổ để trở lại tập luyện thể thao.', '<h2>1. Tầm quan trọng của phục hồi chức năng sau mổ ACL</h2>
INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('020f45b8-3082-49cc-b159-a27277e65d69', 'Bài tập vật lý trị liệu giảm đau vai gáy tại nhà hiệu quả', 'bai-tap-vat-ly-tri-lieu-giam-dau-vai-gay-tai-nha', 'Đau mỏi vai gáy tê bì vai cổ gây khó chịu, đau đầu mất ngủ. Dưới đây là 5 bài tập kéo giãn cơ đơn giản bạn có thể tập luyện tại nhà hoặc ngay tại văn phòng để giải phóng căng thẳng cơ vùng cổ.', '<h2>1. Nguyên nhân gây đau mỏi cổ vai gáy thường gặp</h2>
INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('c915a328-37da-4a8b-9250-8025d2bcb739', 'Cách nhận biết và điều trị vẹo cột sống học đường ở trẻ em', 'cach-nhan-biet-veo-cot-song-hoc-duong', 'Vẹo cột sống học đường ở trẻ em tiến triển rất âm thầm và gây ra những biến dạng cơ thể vĩnh viễn nếu phát hiện muộn. Cha mẹ cần chú ý kiểm tra tư thế của con thường xuyên để có biện pháp can thiệp sớm.', '<h2>1. Thực trạng vẹo cột sống học đường</h2>
INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('b8660bf0-d2d4-43ef-b9e2-f8d2ffacc75c', 'Phục hồi chức năng hô hấp cho bệnh nhân sau tổn thương phổi', 'phuc-hoi-chuc-nang-ho-hap', 'Các tổn thương phổi sau viêm phổi nặng, COPD hoặc hậu vi rút để lại di chứng khó thở, giảm thể tích phổi. Phục hồi chức năng hô hấp giúp khôi phục dung tích sống của phổi nhanh chóng.', '<h2>1. Tại sao cần phục hồi chức năng phổi?</h2>
INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('cb6c77f8-4d5a-4aa7-b2a6-74a3358a5a03', 'Liệu pháp nhiệt nóng và nhiệt lạnh trong chấn thương thể thao', 'lieu-phap-nhiet-nong-lanh-chan-thuong-the-thao', 'Khi bị chấn thương thể thao như bong gân hay căng cơ, việc lựa chọn chườm nóng hay chườm lạnh quyết định tốc độ hồi phục. Sai lầm trong việc chườm nhiệt có thể khiến vết thương sưng viêm nặng hơn.', '<h2>1. Chườm lạnh: Giải pháp cứu cánh cho chấn thương cấp tính</h2>
INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('11f7e3ba-b023-4ec2-88c6-cb817b97b477', 'Cách khắc phục chứng mất ngủ do đau mỏi cổ vai gáy mãn tính', 'khac-phuc-mat-ngu-do-dau-co-vai-gay-man-tinh', 'Đau mỏi cổ vai gáy mãn tính kéo dài là thủ phạm hàng đầu cướp đi giấc ngủ sâu của bạn. Tìm hiểu các giải pháp vật lý trị liệu giúp giảm đau nhức cổ và cải thiện chất lượng giấc ngủ tối ưu.', '<h2>1. Mối liên hệ mật thiết giữa đau cổ và mất ngủ</h2>
INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('ca203770-3541-4ef7-ba28-bca7bbed5103', 'Tác hại của việc ngồi sai tư thế làm việc và giải pháp chỉnh sửa', 'tac-hai-ngoi-sai-tu-the-va-giai-phap', 'Ngồi cong lưng, cúi sát màn hình hay bắt chéo chân là thói quen xấu tàn phá cột sống của bạn mỗi ngày. Hãy học cách chỉnh sửa tư thế ngồi chuẩn để bảo vệ sức khỏe hệ xương khớp.', '<h2>1. Những thói quen ngồi làm việc sai tư thế cực kỳ tai hại</h2>
INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('4d766b60-8d12-4002-a8ff-2935c4d01dc0', 'Tầm quan trọng của việc giãn cơ sau khi tập luyện thể thao cường độ cao', 'tam-quan-trong-gian-co-sau-tap-luyen', 'Bỏ qua bước giãn cơ sau khi tập luyện là nguyên nhân chính gây ra các chấn thương gân cơ nghiêm trọng và tình trạng đau mỏi cơ kéo dài nhiều ngày. Khám phá lợi ích kỳ diệu của giãn cơ tĩnh.', '<img src="/uploads/blog/340d2f87-54f4-461b-a368-ade92621b6a7.webp" /><h2>1. Hiện tượng co cơ sau vận động cường độ cao</h2><p>Khi chơi các môn thể thao vận động mạnh như chạy bộ, đá bóng, tập tạ, các sợi cơ liên tục co thắt và hình thành các vết rách vi thể. Axit lactic tích tụ trong tế bào cơ chính là thủ phạm gây ra cảm giác đau nhức ê ẩm dữ dội vào ngày hôm sau (Hiện tượng DOMS).</p><h2>2. Lợi ích vượt trội của việc giãn cơ tĩnh (Static Stretching)</h2><ul><li><p><strong>Đào thải Axit Lactic:</strong> Giúp máu lưu thông nhanh chóng mang axit lactic ra khỏi mô cơ.</p></li><li><p><strong>Phục hồi chiều dài sinh lý của cơ:</strong> Tránh tình trạng xơ hóa cơ, giúp các cơ bắp luôn thon gọn, dẻo dai và hạn chế căng cơ bong gân ở lần tập tiếp theo.</p></li></ul><h2>3. Hướng dẫn giãn cơ tĩnh đúng cách</h2><p>Giãn cơ tĩnh nên thực hiện ngay sau buổi tập khi cơ thể còn ấm nóng. Giữ mỗi tư thế giãn cơ từ 20 đến 30 giây ở mức căng vừa phải, tuyệt đối không giật cục mạnh tránh làm rách cơ.</p>', '/Baiviet/images/vat_ly_tri_lieu_cover.png', 'suc_khoe', 'xuat_ban', 'Tầm quan trọng giãn cơ sau khi chơi thể thao', 'Tại sao giãn cơ sau khi tập luyện lại cực kỳ cần thiết để hồi phục cơ bắp và tránh chấn thương gân cơ.', 'gian co, cool down, dau moi co, phuc hoi co bap', 792, 5, '2026-07-17T05:21:29.600Z', '2026-07-17T05:21:29.600Z', '2026-07-22T16:30:03.637Z');
INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('d60ab1e3-0e63-45f2-9bf3-654c26a3bc94', 'Phục hồi chức năng sau tai biến mạch máu não: Thời điểm vàng và lộ trình', 'phuc-hoi-chuc-nang-sau-tai-bien-mach-mau-nao', 'Tai biến mạch máu não để lại nhiều di chứng nặng nề như liệt nửa người, khó nói, mất thăng bằng. Phục hồi chức năng sớm trong giai đoạn vàng quyết định khả năng tái hòa nhập cộng đồng của bệnh nhân.', '<img src="/uploads/blog/322648bb-76de-415d-bddc-9d636109cf20.webp" /><h2>1. Tầm quan trọng của Phục hồi chức năng sau tai biến</h2><p>Sau cơn tai biến mạch máu não (đột quỵ), các tế bào não tại vùng bị tổn thương sẽ chết đi, dẫn đến mất kiểm soát các vùng cơ tương ứng. Tuy nhiên, nhờ vào khả năng thích ứng linh hoạt của não bộ (Neuroplasticity), các vùng não lành xung quanh có thể học cách đảm nhiệm thay vai trò của vùng não đã mất nếu được kích thích đúng cách thông qua phục hồi chức năng.</p><h2>2. Thời điểm vàng để bắt đầu trị liệu</h2><p>Giai đoạn vàng để bắt đầu phục hồi chức năng là từ <strong>3 đến 6 tháng đầu tiên</strong> sau khi bệnh nhân qua cơn nguy kịch và các chỉ số sinh tồn đã ổn định. Trị liệu càng sớm, tỷ lệ phục hồi vận động và ngôn ngữ càng cao, ngăn ngừa hiệu quả biến chứng co rút cơ, cứng khớp.</p><h2>3. Lộ trình phục hồi chức năng đa chuyên khoa</h2><p>Một chương trình phục hồi toàn diện bao gồm nhiều giai đoạn phối hợp chặt chẽ:</p><ul><li><p><strong>Vận động trị liệu (Physical Therapy):</strong> Tập trung vào việc tập ngồi, tập đứng, tập đi và khôi phục sức mạnh các nhóm cơ bị liệt.</p></li><li><p><strong>Hoạt động trị liệu (Occupational Therapy):</strong> Hướng dẫn bệnh nhân tự thực hiện các sinh hoạt hàng ngày như ăn uống, mặc quần áo, đánh răng, tắm rửa.</p></li><li><p><strong>Ngôn ngữ trị liệu (Speech Therapy):</strong> Cải thiện chức năng nuốt và phục hồi khả năng phát âm, giao tiếp đối với những bệnh nhân bị tổn thương vùng Broca của não bộ.</p></li></ul><p></p>', '/Baiviet/images/vat_ly_tri_lieu_cover.png', 'suc_khoe', 'xuat_ban', 'Thời điểm vàng phục hồi chức năng sau tai biến', 'Lộ trình phục hồi chức năng toàn diện cho bệnh nhân sau tai biến mạch máu não giai đoạn vàng.', 'tai bien, dot quy, phuc hoi liet, tai hoa nhap', 374, 5, '2026-07-17T05:21:29.556Z', '2026-07-17T05:21:29.556Z', '2026-07-19T11:22:52.158Z');
INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('16539e27-d1c5-40b9-8808-abf66bea58ba', 'Phục hồi chức năng sau chấn thương cổ chân (lật sơ mi) đúng cách', 'phuc-hoi-chan-thuong-co-chan-lat-so-mi', 'Bong gân cổ chân hay lật sơ mi là chấn thương thể thao vô cùng phổ biến. Nếu không được phục hồi chức năng đúng cách, cổ chân sẽ bị yếu mãn tính và rất dễ lật đi lật lại nhiều lần.', '<h2>1. Bản chất chấn thương lật sơ mi cổ chân</h2>
INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('1ab28171-5803-40a2-ad78-b2028ad8c854', 'Cách phòng ngừa hội chứng ống cổ tay cho nhân viên văn phòng', 'phong-ngua-hoi-chung-ong-co-tay-dan-van-phong', 'Sử dụng chuột và bàn phím sai tư thế trong nhiều giờ liền khiến dây thần kinh giữa bị chèn ép, dẫn đến hội chứng ống cổ tay tê bì tay. Tìm hiểu ngay những tư thế chuẩn và bài tập phòng tránh hiệu quả.', '<h2>1. Tại sao dân văn phòng dễ mắc hội chứng ống cổ tay?</h2>
INSERT INTO "bai_viet" ("id", "tieu_de", "slug", "tom_tat", "noi_dung", "anh_bia", "danh_muc", "trang_thai", "meta_title", "meta_description", "meta_keywords", "luot_xem", "nguoi_viet_id", "ngay_dang", "ngay_tao", "ngay_cap_nhat") VALUES ('895d0536-eb07-4cce-97b1-e59fc08ed9c0', 'Vật lý trị liệu cho người bị thần kinh tọa: Những lưu ý quan trọng', 'vat-ly-tri-lieu-dau-than-kinh-toa', 'Đau thần kinh tọa gây ra cơn đau buốt dọc từ hông xuống bắp chân. Việc tập luyện vật lý trị liệu đúng cách giúp giải nén dây thần kinh và phục hồi chức năng đi lại nhanh chóng.', '<h2>1. Hiểu về đau thần kinh tọa</h2>
