INSERT INTO "danh_gia_goi_dich_vu" ("id", "khach_hang_id", "goi_dich_vu_id", "cuoc_hen_id", "so_sao", "nhan_xet", "ngay_tao", "ngay_cap_nhat", "ngay_phan_hoi", "nguoi_phan_hoi_id", "phan_hoi_nhan_xet", "cam_xuc", "do_tin_cay", "ly_do_cam_xuc", "de_xuat_hanh_dong", "de_xuat_phan_hoi") VALUES ('9cdb172f-2472-438c-9337-d3ac2a2b33db', 'fe0a3a4b-a6f4-46d5-9229-30a525289cdb', 'c1000000-0000-0000-0000-000000000000', NULL, 5, 'dsad', '2026-07-17T11:31:53.889Z', '2026-07-17T12:39:29.913Z', NULL, NULL, NULL, 'NEUTRAL', 0.85, 'Nội dung đánh giá chứa ký tự ngẫu nhiên, không có thông tin rõ ràng để kết luận cảm xúc dù khách chấm 5 sao.', 'Chưa cần thực hiện hành động xử lý đặc biệt nào. Admin chỉ cần trả lời cảm ơn xã giao.', 'Phòng khám OfficeCare xin cảm ơn Anh/Chị đã gửi phản hồi. Nếu Anh/Chị cần tư vấn hoặc hỗ trợ thêm về dịch vụ vật lý trị liệu, xin vui lòng liên hệ hotline của phòng khám nhé.');
INSERT INTO "danh_gia_goi_dich_vu" ("id", "khach_hang_id", "goi_dich_vu_id", "cuoc_hen_id", "so_sao", "nhan_xet", "ngay_tao", "ngay_cap_nhat", "ngay_phan_hoi", "nguoi_phan_hoi_id", "phan_hoi_nhan_xet", "cam_xuc", "do_tin_cay", "ly_do_cam_xuc", "de_xuat_hanh_dong", "de_xuat_phan_hoi") VALUES ('8390c5d6-eeb4-4ed6-b8cb-b641d090a54b', '10000000-0000-0000-0000-000000000011', 'c1000000-0000-0000-0000-000000000000', NULL, 3, 'Dịch vụ quá tệ ', '2026-07-17T05:09:31.142Z', '2026-07-22T15:19:16.854Z', NULL, NULL, NULL, 'NEGATIVE', 0.95, 'Khách hàng nhận xét dịch vụ ''quá tệ'', thể hiện sự không hài lòng rõ rệt về chất lượng trải nghiệm tại phòng khám.', 'Lễ tân/Admin nên chủ động liên hệ trực tiếp với khách hàng để tìm hiểu nguyên nhân cụ thể và gửi lời xin lỗi chân thành.', 'Phòng khám OfficeCare chân thành xin lỗi Anh/Chị vì trải nghiệm chưa tốt tại phòng khám. Chúng em rất mong muốn lắng nghe chia sẻ chi tiết từ Anh/Chị để khắc phục và nâng cao chất lượng dịch vụ. Anh/Chị vui lòng liên hệ hotline của OfficeCare để được hỗ trợ trực tiếp nhanh nhất ạ.');
INSERT INTO "danh_gia_goi_dich_vu" ("id", "khach_hang_id", "goi_dich_vu_id", "cuoc_hen_id", "so_sao", "nhan_xet", "ngay_tao", "ngay_cap_nhat", "ngay_phan_hoi", "nguoi_phan_hoi_id", "phan_hoi_nhan_xet", "cam_xuc", "do_tin_cay", "ly_do_cam_xuc", "de_xuat_hanh_dong", "de_xuat_phan_hoi") VALUES ('9da150a5-7948-4e49-af63-31a826d0bca4', '65e5a742-bd47-4ebe-9e02-d3adc719a100', 'c1000000-0000-0000-0000-000000000103', NULL, 5, 'KTV Nam hỗ trợ trị liệu nhiệt lạnh cực kỳ chu đáo. Cảm ơn phòng khám rất nhiều.', '2026-07-16T02:27:41.802Z', '2026-07-16T02:27:41.802Z', NULL, NULL, NULL, 'POSITIVE', 0.99, 'Khách hàng dành 5 sao và bày tỏ sự hài lòng, khen ngợi sự chu đáo của kỹ thuật viên Nam cũng như gửi lời cảm ơn tới phòng khám.', 'Ghi nhận và biểu dương KTV Nam vì thái độ phục vụ tốt, đồng thời đăng câu trả lời cảm ơn khách hàng trên hệ thống.', 'Cảm ơn Anh/Chị đã tin tưởng trải nghiệm dịch vụ tại Phòng khám OfficeCare. Phòng khám rất vui khi biết KTV Nam đã hỗ trợ Anh/Chị tận tình trong liệu trình trị liệu nhiệt lạnh. Kính chúc Anh/Chị luôn nhiều sức khỏe và chóng phục hồi!');
INSERT INTO "danh_gia_goi_dich_vu" ("id", "khach_hang_id", "goi_dich_vu_id", "cuoc_hen_id", "so_sao", "nhan_xet", "ngay_tao", "ngay_cap_nhat", "ngay_phan_hoi", "nguoi_phan_hoi_id", "phan_hoi_nhan_xet", "cam_xuc", "do_tin_cay", "ly_do_cam_xuc", "de_xuat_hanh_dong", "de_xuat_phan_hoi") VALUES ('6cd51ab0-832b-4867-ae0f-313ef937616b', '10000000-0000-0000-0000-000000000013', 'c1000000-0000-0000-0000-000000000102', NULL, 4, 'Chi phí hợp lý, phục vụ nhanh chóng chuyên nghiệp. Bác sĩ tư vấn phác đồ rõ ràng, không vẽ vời.', '2026-07-16T02:27:41.795Z', '2026-07-16T02:27:41.795Z', NULL, NULL, NULL, 'POSITIVE', 0.98, 'Khách hàng hài lòng về chi phí hợp lý, dịch vụ nhanh chóng chuyên nghiệp và bác sĩ tư vấn phác đồ rõ ràng.', 'Ghi nhận và biểu dương đội ngũ bác sĩ, nhân viên phục vụ; có thể gửi tin nhắn cảm ơn khách hàng.', 'Phòng khám OfficeCare xin cảm ơn Anh/Chị đã tin tưởng và trải nghiệm dịch vụ. Sự hài lòng của Anh/Chị về chi phí, chất lượng phục vụ và phác đồ điều trị của bác sĩ là động lực rất lớn cho đội ngũ phòng khám. Chúc Anh/Chị luôn dồi dào sức khỏe!');
INSERT INTO "danh_gia_goi_dich_vu" ("id", "khach_hang_id", "goi_dich_vu_id", "cuoc_hen_id", "so_sao", "nhan_xet", "ngay_tao", "ngay_cap_nhat", "ngay_phan_hoi", "nguoi_phan_hoi_id", "phan_hoi_nhan_xet", "cam_xuc", "do_tin_cay", "ly_do_cam_xuc", "de_xuat_hanh_dong", "de_xuat_phan_hoi") VALUES ('523f9f30-7fa2-440e-8f72-0d58838240df', '10000000-0000-0000-0000-000000000012', 'c1000000-0000-0000-0000-000000000101', NULL, 5, 'Liệu trình kéo giãn cột sống bằng máy áp lực âm rất hiệu quả, tôi đỡ hẳn đau cổ. Máy móc rất xịn.', '2026-07-16T02:27:41.789Z', '2026-07-16T02:27:41.789Z', NULL, NULL, NULL, 'POSITIVE', 0.99, 'Khách hàng chấm 5 sao và khen ngợi liệu trình hiệu quả giúp giảm hẳn đau cổ cũng như đánh giá cao trang thiết bị hiện đại.', 'Lễ tân gửi phản hồi cảm ơn khách hàng, đồng thời chia sẻ đánh giá này tới đội ngũ chuyên môn để động viên tinh thần.', 'Phòng khám OfficeCare chân thành cảm ơn Anh/Chị đã tin tưởng và sử dụng dịch vụ. Phòng khám rất vui khi biết liệu trình kéo giãn cột sống mang lại hiệu quả tốt và giúp Anh/Chị thuyên giảm cơn đau cổ. Chúc Anh/Chị luôn có nhiều sức khỏe và OfficeCare rất hân hạnh được tiếp tục đồng hành cùng Anh/Chị!');
INSERT INTO "danh_gia_goi_dich_vu" ("id", "khach_hang_id", "goi_dich_vu_id", "cuoc_hen_id", "so_sao", "nhan_xet", "ngay_tao", "ngay_cap_nhat", "ngay_phan_hoi", "nguoi_phan_hoi_id", "phan_hoi_nhan_xet", "cam_xuc", "do_tin_cay", "ly_do_cam_xuc", "de_xuat_hanh_dong", "de_xuat_phan_hoi") VALUES ('1b63873d-3c62-4b20-841e-719d96581cea', '10000000-0000-0000-0000-000000000014', 'c1000000-0000-0000-0000-000000000000', NULL, 5, 'Tôi đã điều trị đau lưng ở đây, các chuyên viên rất tận tâm và tay nghề giỏi. Phòng khám sạch sẽ, thoáng mát.', '2026-07-16T02:27:41.780Z', '2026-07-16T02:27:41.780Z', NULL, NULL, NULL, 'POSITIVE', 0.98, 'Khách hàng rất hài lòng về hiệu quả điều trị đau lưng, thái độ tận tâm, tay nghề của chuyên viên cũng như không gian phòng khám sạch sẽ.', 'Lễ tân ghi nhận biểu dương kỹ thuật viên phụ trách, đồng thời gửi tin nhắn cảm ơn và có thể nhờ khách chia sẻ thêm trải nghiệm trên Google Maps/Facebook.', 'Phòng khám OfficeCare chân thành cảm ơn Anh/Chị đã tin tưởng điều trị và dành lời khen quý báu cho đội ngũ chuyên viên cũng như cơ sở vật chất của chúng tôi. Sự phục hồi và hài lòng của Anh/Chị chính là động lực lớn nhất để OfficeCare không ngừng hoàn thiện. Chúc Anh/Chị luôn dồi dào sức khỏe và duy trì thể trạng tốt nhất!');
INSERT INTO "danh_gia_goi_dich_vu" ("id", "khach_hang_id", "goi_dich_vu_id", "cuoc_hen_id", "so_sao", "nhan_xet", "ngay_tao", "ngay_cap_nhat", "ngay_phan_hoi", "nguoi_phan_hoi_id", "phan_hoi_nhan_xet", "cam_xuc", "do_tin_cay", "ly_do_cam_xuc", "de_xuat_hanh_dong", "de_xuat_phan_hoi") VALUES ('2173d36a-d35d-4c01-a526-c68f0539698e', 'd5d1baf4-628a-4622-ba35-95da33c19c16', 'c1000000-0000-0000-0000-000000000000', NULL, 5, 'ok tốt', '2026-07-16T04:24:26.974Z', '2026-07-21T12:25:50.994Z', '2026-07-22T15:01:53.479Z', 1, 'Phòng khám OfficeCare xin chân thành cảm ơn Anh/Chị đã tin tưởng và dành thời gian đánh giá dịch vụ. Sự hài lòng của Anh/Chị là động lực rất lớn để đội ngũ phòng khám tiếp tục nâng cao chất lượng phục vụ. Chúc Anh/Chị luôn dồi dào sức khỏe và mong sớm được đón tiếp Anh/Chị trong lần tái khám tới.', 'POSITIVE', 0.95, 'Khách hàng chấm điểm tuyệt đối 5/5 và để lại phản hồi tích cực ngắn gọn thể hiện sự hài lòng.', 'Lễ tân phản hồi cảm ơn khách hàng và tiếp tục duy trì chất lượng dịch vụ tốt.', 'Phòng khám OfficeCare xin chân thành cảm ơn Anh/Chị đã tin tưởng và dành thời gian đánh giá dịch vụ. Sự hài lòng của Anh/Chị là động lực rất lớn để đội ngũ phòng khám tiếp tục nâng cao chất lượng phục vụ. Chúc Anh/Chị luôn dồi dào sức khỏe và mong sớm được đón tiếp Anh/Chị trong lần tái khám tới.');
INSERT INTO "danh_gia_nhan_su" ("id", "khach_hang_id", "nhan_su_id", "cuoc_hen_id", "so_sao", "nhan_xet", "ngay_tao", "ngay_cap_nhat", "ngay_phan_hoi", "nguoi_phan_hoi_id", "phan_hoi_nhan_xet", "cam_xuc", "do_tin_cay", "ly_do_cam_xuc", "de_xuat_hanh_dong", "de_xuat_phan_hoi") VALUES ('17fab692-03c3-449b-8335-46cae33b2762', 'd5d1baf4-628a-4622-ba35-95da33c19c16', 5, NULL, 5, 'Bác Sĩ Tận Tình Tận Tâm', '2026-07-16T04:24:26.959Z', '2026-07-16T04:25:24.626Z', NULL, NULL, NULL, 'POSITIVE', 0.98, 'Khách hàng đánh giá 5 sao và khen ngợi bác sĩ tận tình, tận tâm.', NULL, NULL);
INSERT INTO "danh_gia_nhan_su" ("id", "khach_hang_id", "nhan_su_id", "cuoc_hen_id", "so_sao", "nhan_xet", "ngay_tao", "ngay_cap_nhat", "ngay_phan_hoi", "nguoi_phan_hoi_id", "phan_hoi_nhan_xet", "cam_xuc", "do_tin_cay", "ly_do_cam_xuc", "de_xuat_hanh_dong", "de_xuat_phan_hoi") VALUES ('823d1311-605b-4d62-9f9c-35de4c48247b', '10000000-0000-0000-0000-000000000011', 5, NULL, 5, 'ok', '2026-07-17T05:09:31.132Z', '2026-07-17T05:09:31.132Z', NULL, NULL, NULL, 'POSITIVE', 0.85, 'Khách hàng chấm điểm tối đa 5/5 sao cùng bình luận đồng ý, thể hiện sự hài lòng với dịch vụ dù nội dung ngắn gọn.', NULL, NULL);
