INSERT INTO "danh_gia_nhan_su" ("id", "khach_hang_id", "nhan_su_id", "cuoc_hen_id", "so_sao", "nhan_xet", "ngay_tao", "ngay_cap_nhat", "ngay_phan_hoi", "nguoi_phan_hoi_id", "phan_hoi_nhan_xet", "cam_xuc", "do_tin_cay", "ly_do_cam_xuc", "de_xuat_hanh_dong", "de_xuat_phan_hoi") VALUES ('dea7c3d8-6bac-49a3-aa35-c11ef5d92b20', 'fe0a3a4b-a6f4-46d5-9229-30a525289cdb', 5, NULL, 5, 'dsa', '2026-07-17T12:39:29.887Z', '2026-07-17T12:39:29.887Z', NULL, NULL, NULL, 'NEUTRAL', 0.85, 'Nội dung đánh giá chỉ chứa ký tự ngẫu nhiên, không có thông tin cụ thể để xác định cảm xúc thực tế của khách hàng.', 'Ghi nhận đánh giá trên hệ thống và không cần thực hiện hành động xử lý đặc biệt.', NULL);
INSERT INTO "danh_gia_nhan_su" ("id", "khach_hang_id", "nhan_su_id", "cuoc_hen_id", "so_sao", "nhan_xet", "ngay_tao", "ngay_cap_nhat", "ngay_phan_hoi", "nguoi_phan_hoi_id", "phan_hoi_nhan_xet", "cam_xuc", "do_tin_cay", "ly_do_cam_xuc", "de_xuat_hanh_dong", "de_xuat_phan_hoi") VALUES ('673302bc-814c-4e34-a0a7-a3adc8439f59', '10000000-0000-0000-0000-000000000014', 7, NULL, 5, 'Tôi đã điều trị đau lưng ở đây, các chuyên viên rất tận tâm và tay nghề giỏi. Phòng khám sạch sẽ, thoáng mát.', '2026-07-16T02:27:41.784Z', '2026-07-16T02:27:41.784Z', NULL, NULL, NULL, 'POSITIVE', 0.99, 'Khách hàng khen ngợi chuyên viên tận tâm, tay nghề giỏi và phòng khám sạch sẽ, đi kèm đánh giá 5 sao.', NULL, NULL);
INSERT INTO "danh_gia_nhan_su" ("id", "khach_hang_id", "nhan_su_id", "cuoc_hen_id", "so_sao", "nhan_xet", "ngay_tao", "ngay_cap_nhat", "ngay_phan_hoi", "nguoi_phan_hoi_id", "phan_hoi_nhan_xet", "cam_xuc", "do_tin_cay", "ly_do_cam_xuc", "de_xuat_hanh_dong", "de_xuat_phan_hoi") VALUES ('9b790661-fcda-41ec-a465-145e60e3fb45', '10000000-0000-0000-0000-000000000012', 8, NULL, 5, 'Liệu trình kéo giãn cột sống bằng máy áp lực âm rất hiệu quả, tôi đỡ hẳn đau cổ. Máy móc rất xịn.', '2026-07-16T02:27:41.791Z', '2026-07-16T02:27:41.791Z', NULL, NULL, NULL, 'POSITIVE', 0.98, 'Khách hàng khen liệu trình rất hiệu quả, giảm hẳn đau cổ và đánh giá máy móc chất lượng cao.', NULL, NULL);
INSERT INTO "danh_gia_nhan_su" ("id", "khach_hang_id", "nhan_su_id", "cuoc_hen_id", "so_sao", "nhan_xet", "ngay_tao", "ngay_cap_nhat", "ngay_phan_hoi", "nguoi_phan_hoi_id", "phan_hoi_nhan_xet", "cam_xuc", "do_tin_cay", "ly_do_cam_xuc", "de_xuat_hanh_dong", "de_xuat_phan_hoi") VALUES ('0452c795-239e-4c5e-a97c-5aa65103d609', '10000000-0000-0000-0000-000000000013', 7, NULL, 4, 'Chi phí hợp lý, phục vụ nhanh chóng chuyên nghiệp. Bác sĩ tư vấn phác đồ rõ ràng, không vẽ vời.', '2026-07-16T02:27:41.797Z', '2026-07-16T02:27:41.797Z', NULL, NULL, NULL, 'POSITIVE', 0.98, 'Khách hàng khen ngợi chi phí hợp lý, dịch vụ nhanh chóng chuyên nghiệp và bác sĩ tư vấn phác đồ rõ ràng.', NULL, NULL);
