INSERT INTO "goi_dich_vu" ("id", "ten_goi", "loai_goi", "tong_so_buoi", "thoi_luong_phut", "don_gia", "don_gia_theo_buoi", "trang_thai", "anh_goi", "anh_gallery", "muc_tieu", "quy_trinh", "han_su_dung_mac_dinh_ngay") VALUES ('c1000000-0000-0000-0000-000000000204', 'Liệu trình Điều chỉnh Tư thế và Cân bằng cơ toàn diện (Posture & Kinetic Core Rehab)', 'LIEU_TRINH', 12, 60, '4200000', '350000', 'hoat_dong', '/images/physio_premium_facility.png', '["/images/physio_premium_facility.png","/goi/images/song_xung_kich.png","/images/therapist_treatment.png"]'::jsonb, 'Khắc phục hoàn toàn tư thế lệch vai, vai tròn, đầu nhô phía trước do dùng máy tính nhiều.
