INSERT INTO "goi_dich_vu" ("id", "ten_goi", "loai_goi", "tong_so_buoi", "thoi_luong_phut", "don_gia", "don_gia_theo_buoi", "trang_thai", "anh_goi", "anh_gallery", "muc_tieu", "quy_trinh", "han_su_dung_mac_dinh_ngay") VALUES ('c1000000-0000-0000-0000-000000000201', 'Liệu trình Chuyên sâu Phục hồi Cổ Vai Gáy Văn phòng (Office Tech-Neck Rehab)', 'LIEU_TRINH', 7, 60, '2200000', '314286', 'hoat_dong', '/images/therapist_treatment.png', '["/images/therapist_treatment.png","/goi/images/giai_co_sau.png","/images/recovery_journey.png"]'::jsonb, 'Chấm dứt hoàn toàn cơn đau mỏi âm ỉ vùng cổ vai gáy mạn tính của dân văn phòng.
