INSERT INTO "ho_so_chuyen_gia" ("id", "nguoi_dung_id", "so_nam_kinh_nghiem", "bang_cap_chung_chi", "mo_ta", "the_manh") VALUES (2, 6, 8, '{"text":"Thạc sĩ Vật lý trị liệu & PHCN - Đại học Y Hà Nội\nChứng chỉ kỹ thuật Laser siêu cao tần và Shockwave hội tụ chuẩn Quốc tế\nChứng chỉ hành nghề Chuyên môn vật lý trị liệu Bộ Y tế cấp","images":["/nhan_su/images/cert_assess.png","/nhan_su/images/cert_physio.png"]}', 'Bác sĩ Trần Thị Thu Trang sở hữu chuyên môn vững vàng trong điều trị các bệnh lý đau mỏi vai gáy cấp và mạn tính của dân công sở. Với 8 năm kinh nghiệm chuyên sâu, bà luôn áp dụng sáng tạo các công nghệ y học vật lý như Laser công suất cao tiêu viêm sâu và sóng xung kích Shockwave phá vỡ các điểm xơ cơ (Trigger Points), mang lại hiệu quả giảm đau tức thì cho bệnh nhân mà không gây đau buốt hay cần can thiệp xâm lấn.', '["Trị liệu hội chứng cổ vai gáy mạn tính","Tiêu viêm rễ thần kinh bằng Laser","Sóng xung kích giải trigger points","Phục hồi chấn thương bả vai"]'::jsonb);
INSERT INTO "ho_so_chuyen_gia" ("id", "nguoi_dung_id", "so_nam_kinh_nghiem", "bang_cap_chung_chi", "mo_ta", "the_manh") VALUES (3, 7, 6, '{"text":"Cử nhân Vật lý trị liệu - Đại học Y Dược TP.HCM\nChứng chỉ kỹ thuật di động khớp khớp cột sống Manual Therapy tiêu chuẩn Úc","images":["/nhan_su/images/cert_physio.png"]}', 'Kỹ thuật viên Lê Văn Dương được mệnh danh là chuyên gia có đôi tay vàng trong trị liệu giải phóng cơ khớp. Với 6 năm kinh nghiệm thực hành trị liệu bằng tay (Manual Therapy) và di động khớp chuyên sâu, anh giúp bệnh nhân khôi phục hoàn toàn biên độ vận động của các khớp đốt sống cổ và thắt lưng bị kẹt do tư thế làm việc gù ngồi kéo dài.', '["Kỹ thuật di động khớp Manual Therapy","Giải cơ sâu Myofascial Release","Nắn khớp thắt lưng giải kẹt","Xoa bóp cơ học y khoa sâu"]'::jsonb);
INSERT INTO "ho_so_chuyen_gia" ("id", "nguoi_dung_id", "so_nam_kinh_nghiem", "bang_cap_chung_chi", "mo_ta", "the_manh") VALUES (5, 9, 4, '{"text":"Chứng chỉ Kỹ thuật viên Vật lý trị liệu Trường Cao đẳng Y tế\nChứng chỉ Vận hành máy trị liệu công nghệ cao Bệnh viện Chợ Rẫy","images":["/nhan_su/images/cert_physio.png"]}', 'Kỹ thuật viên Phạm Thành Nam là chuyên gia vận hành thiết bị vật lý trị liệu hiện đại. Anh chịu trách nhiệm chính điều phối giường kéo giãn cột sống giảm áp áp lực âm kỹ thuật số, cài đặt thông số điện xung giảm đau mỏi lưng dưới. Sự chu đáo và theo dõi thông số chuẩn xác của anh giúp bệnh nhân phục hồi cực kỳ an tâm.', '["Vận hành máy kéo giãn giảm áp","Cài đặt điện xung y khoa","Siêu âm bao gân trị liệu","Theo dõi thông số an toàn thiết bị"]'::jsonb);
INSERT INTO "ho_so_chuyen_gia" ("id", "nguoi_dung_id", "so_nam_kinh_nghiem", "bang_cap_chung_chi", "mo_ta", "the_manh") VALUES (6, 10, 4, '{"text":"Chứng chỉ Kỹ thuật viên Massage trị liệu y học cổ truyền\nChứng chỉ trị liệu giải phóng màng cơ myofascial sâu Viện PHCN","images":["/nhan_su/images/cert_assess.png"]}', 'Kỹ thuật viên Đặng Minh Anh chuyên sâu về trị liệu giải cơ ngực lớn, cơ chéo cổ trước và phục hồi thẩm mỹ tư thế vai tròn gù lưng. Cô áp dụng nhuần nhuyễn sự kết hợp lực tay mềm mại, ấn huyệt kích hoạt lưu thông máu vùng vai cổ giúp bệnh nhân xua tan căng thẳng thể chất lẫn tinh thần sau ngày làm việc bận rộn.', '["Điều chỉnh vai tròn gù lưng","Giải tỏa cơ co thắt ngực/cổ","Massage bấm huyệt trị liệu","Giãn cơ sâu thư giãn vùng gáy"]'::jsonb);
INSERT INTO "ho_so_chuyen_gia" ("id", "nguoi_dung_id", "so_nam_kinh_nghiem", "bang_cap_chung_chi", "mo_ta", "the_manh") VALUES (4, 8, 5, '{"text":"Cử nhân Vật lý trị liệu - PHCN Đại học Y Dược\nChứng chỉ bài tập y khoa phục hồi vận động Kinetic Rehab do Hội PHCN cấp","images":["/nhan_su/images/cert_assess.png"]}', 'Kỹ thuật viên Nguyễn Thùy Linh chuyên trách vận động trị liệu chủ động. Cô có hơn 5 năm kinh nghiệm đồng hành cùng bệnh nhân thực hiện các bài tập Kinetic phục hồi tư thế, tăng cơ lõi core lưng bụng. Cô đặc biệt mát tay trong điều trị bảo tồn hội chứng ống cổ tay cho dân IT, thiết kế đồ họa và kế toán.', '["Vận động trị liệu Kinetic Rehab","Phục hồi hội chứng ống cổ tay","Hướng dẫn tập chỉnh lệch tư thế","Kéo giãn cơ co rút sâu"]'::jsonb);
INSERT INTO "ho_so_chuyen_gia" ("id", "nguoi_dung_id", "so_nam_kinh_nghiem", "bang_cap_chung_chi", "mo_ta", "the_manh") VALUES (1, 5, 12, '{"text":"Bác sĩ Chuyên khoa I PHCN - ĐH Y Dược TP.HCM\nChứng nhận đào tạo Trị liệu thần kinh cột sống Chiropractic y khoa Singapore\nChứng chỉ hành nghề Phục hồi chức năng cơ xương khớp Bộ Y tế cấp","images":["/nhan_su/images/cert_assess.png","/nhan_su/images/cert_physio.png"]}', '- Bác sĩ Nguyễn Minh Đức là chuyên gia hàng đầu về cơ xương khớp cột sống với hơn 12 năm kinh nghiệm thực tế.
