INSERT INTO "nhat_ky_buoi_dieu_tri" ("id", "cuoc_hen_id", "nguoi_tao_id", "vas_truoc", "vas_sau", "chan_doan", "chong_chi_dinh", "ghi_chu", "ngay_tao") VALUES ('d6758b9a-df06-4fb7-978a-79691c8066c6', '1792c038-5524-46f6-ba6b-a751018b4981', 5, NULL, NULL, '123', '231', '21312', '2026-07-20T15:07:16.006Z');
INSERT INTO "nhat_ky_buoi_dieu_tri" ("id", "cuoc_hen_id", "nguoi_tao_id", "vas_truoc", "vas_sau", "chan_doan", "chong_chi_dinh", "ghi_chu", "ngay_tao") VALUES ('3d6b1578-2f01-4b34-bf2e-94d2e8772207', 'c517611c-1197-4fc5-a997-2dddf6a320f7', 5, NULL, NULL, 'ok', 'ok', NULL, '2026-07-20T15:48:30.555Z');
INSERT INTO "nhat_ky_buoi_dieu_tri" ("id", "cuoc_hen_id", "nguoi_tao_id", "vas_truoc", "vas_sau", "chan_doan", "chong_chi_dinh", "ghi_chu", "ngay_tao") VALUES ('d0f4abbf-350f-4e89-b612-63b590db862c', '430c5cb7-6833-4f17-b339-6a0bd0b0a447', 5, NULL, NULL, 'kmlk', 'jkl;', 'ok', '2026-07-20T15:56:46.433Z');
INSERT INTO "nhat_ky_buoi_dieu_tri" ("id", "cuoc_hen_id", "nguoi_tao_id", "vas_truoc", "vas_sau", "chan_doan", "chong_chi_dinh", "ghi_chu", "ngay_tao") VALUES ('9adcfc55-efbb-452b-ad82-b40f2555cb54', 'd92d67a5-cb21-4c09-8cea-b740a4b879dc', 7, 2, 1, 'Hoàn thành liệu trình 10 buổi. Hết đau thắt lưng khi sinh hoạt/làm việc bình thường, tư thế ngồi cải thiện rõ rệt, biên độ vận động cột sống thắt lưng trở lại bình thường.', NULL, 'Tổng kết liệu trình: đáp ứng điều trị tốt, thang điểm đau VAS giảm từ 8 xuống 1. Khuyến nghị duy trì bài tập core tại nhà, tái khám sau 1-2 tháng nếu có dấu hiệu tái phát.', '2026-07-20T16:52:55.633Z');
INSERT INTO "nhat_ky_buoi_dieu_tri" ("id", "cuoc_hen_id", "nguoi_tao_id", "vas_truoc", "vas_sau", "chan_doan", "chong_chi_dinh", "ghi_chu", "ngay_tao") VALUES ('e9a70629-7e04-4f59-b632-ef90c1b4c309', '090544a7-f13e-4439-a7dd-7dcfb58751a0', 7, 3, 1, 'Triệu chứng đau thắt lưng gần như hết, tư thế sinh hoạt đã ổn định.', NULL, 'Chuẩn bị kết thúc liệu trình: đánh giá lại toàn diện, biên độ vận động cột sống thắt lưng trở về gần như bình thường.', '2026-07-20T16:52:55.633Z');
INSERT INTO "nhat_ky_buoi_dieu_tri" ("id", "cuoc_hen_id", "nguoi_tao_id", "vas_truoc", "vas_sau", "chan_doan", "chong_chi_dinh", "ghi_chu", "ngay_tao") VALUES ('6aa67cb1-bcd0-4520-a666-edfd546bbfc1', '655d6f9b-5456-4dfc-bc90-88252af842a0', 10, 4, 2, 'Không còn đau khi sinh hoạt bình thường, chỉ mỏi nhẹ khi ngồi liên tục trên 2 giờ.', NULL, 'Duy trì kéo giãn + bài tập core. Khách báo cáo ngủ ngon hơn, không còn thức giấc vì đau lưng.', '2026-07-20T16:52:55.633Z');
INSERT INTO "nhat_ky_buoi_dieu_tri" ("id", "cuoc_hen_id", "nguoi_tao_id", "vas_truoc", "vas_sau", "chan_doan", "chong_chi_dinh", "ghi_chu", "ngay_tao") VALUES ('ade249d5-2e3c-49df-ac9c-9ba7b3543971', 'c2b145c8-5711-4199-bf52-4cdceecee15d', 7, 5, 2, 'Gần như hết đau, thỉnh thoảng còn mỏi nhẹ cuối ngày.', NULL, 'Tăng cường bài tập tăng sức bền cơ lưng. Khách tự tin vận động hơn, không còn e ngại cúi gập người.', '2026-07-20T16:52:55.633Z');
INSERT INTO "nhat_ky_buoi_dieu_tri" ("id", "cuoc_hen_id", "nguoi_tao_id", "vas_truoc", "vas_sau", "chan_doan", "chong_chi_dinh", "ghi_chu", "ngay_tao") VALUES ('d812380b-e302-4caf-b387-aa9f043e4027', '91eba482-697a-4831-b583-343cdce3e8c2', 7, 5, 3, 'Đau thắt lưng nhẹ, không còn co cứng cơ rõ rệt.', NULL, 'Tập trung tái định hình tư thế đứng/ngồi. Hướng dẫn điều chỉnh màn hình và ghế làm việc phù hợp công thái học.', '2026-07-20T16:52:55.633Z');
INSERT INTO "nhat_ky_buoi_dieu_tri" ("id", "cuoc_hen_id", "nguoi_tao_id", "vas_truoc", "vas_sau", "chan_doan", "chong_chi_dinh", "ghi_chu", "ngay_tao") VALUES ('f03e82b3-7403-4173-a321-ac728b14840a', '3f116dff-0f1b-4456-a21c-50c80dddeaca', 7, 6, 3, 'Đau thắt lưng thoáng qua, chủ yếu khi ngồi sai tư thế đột ngột.', NULL, 'Giữa liệu trình: đánh giá lại tầm vận động cột sống thắt lưng, cải thiện khoảng 70% so với ban đầu. Tiếp tục duy trì bài tập core.', '2026-07-20T16:52:55.633Z');
INSERT INTO "nhat_ky_buoi_dieu_tri" ("id", "cuoc_hen_id", "nguoi_tao_id", "vas_truoc", "vas_sau", "chan_doan", "chong_chi_dinh", "ghi_chu", "ngay_tao") VALUES ('6bd99cda-efcb-4cfe-bdf0-7f75e2fcdbbf', '8fde9f1a-da80-4759-8af8-3433b370a683', 10, 6, 4, 'Đau thắt lưng nhẹ, chủ yếu về cuối ngày làm việc. Tư thế ngồi đã cải thiện.', NULL, 'KTV thay ca: tiếp tục phác đồ, bổ sung điện xung giảm đau kết hợp kéo giãn. Khách đáp ứng tốt, không ghi nhận tác dụng phụ.', '2026-07-20T16:52:55.633Z');
INSERT INTO "nhat_ky_buoi_dieu_tri" ("id", "cuoc_hen_id", "nguoi_tao_id", "vas_truoc", "vas_sau", "chan_doan", "chong_chi_dinh", "ghi_chu", "ngay_tao") VALUES ('b7217ee1-b3b2-4e60-a903-360863d75b8c', '8977c846-87d1-414c-85b5-69ca8e3d9c86', 7, 7, 4, 'Đau thắt lưng giảm rõ, biên độ vận động cải thiện, còn hơi cứng khi mới ngủ dậy.', NULL, 'Tăng cường độ kéo giãn cơ học. Thực hiện thêm bài tập core ổn định cột sống. Khách tuân thủ tốt bài tập tại nhà.', '2026-07-20T16:52:55.633Z');
INSERT INTO "nhat_ky_buoi_dieu_tri" ("id", "cuoc_hen_id", "nguoi_tao_id", "vas_truoc", "vas_sau", "chan_doan", "chong_chi_dinh", "ghi_chu", "ngay_tao") VALUES ('ea0337ed-1c11-4ecb-ac4f-c8c13781bb9e', 'a82dde39-6532-4b57-b75a-30b8c1ce92da', 7, 7, 5, 'Đau thắt lưng mức độ vừa, giảm nhẹ so với buổi đầu, còn co cứng cơ vùng thắt lưng dưới.', NULL, 'Tiếp tục kéo giãn cơ học + xoa bóp trị liệu vùng cạnh sống. Khách phản hồi đỡ đau hơn khi ngồi lâu. Bổ sung bài tập kéo giãn gân kheo tại nhà.', '2026-07-20T16:52:55.633Z');
INSERT INTO "nhat_ky_buoi_dieu_tri" ("id", "cuoc_hen_id", "nguoi_tao_id", "vas_truoc", "vas_sau", "chan_doan", "chong_chi_dinh", "ghi_chu", "ngay_tao") VALUES ('bf83a01e-13d1-4652-b432-a40da363c047', '123c614e-9996-446e-9d0e-74ea704b06a5', 7, 8, 6, 'Đau thắt lưng mãn tính do ngồi sai tư thế văn phòng kéo dài, kèm co cứng cơ cạnh sống thắt lưng và hạn chế gập người ra trước.', NULL, 'Buổi đầu liệu trình: đánh giá tổng quát, thực hiện kéo giãn cột sống thắt lưng bằng máy + nhiệt trị liệu sâu. Khách còn cứng cơ rõ, biên độ gập người hạn chế khoảng 60%. Hướng dẫn tư thế ngồi làm việc đúng.', '2026-07-20T16:52:55.633Z');
INSERT INTO "nhat_ky_buoi_dieu_tri" ("id", "cuoc_hen_id", "nguoi_tao_id", "vas_truoc", "vas_sau", "chan_doan", "chong_chi_dinh", "ghi_chu", "ngay_tao") VALUES ('bbbf423a-e9ef-4997-a732-697c75ce287d', 'f8d43fea-4842-4e93-92b4-4669b5b5f0d9', 5, NULL, NULL, 'ok', 'kok', 'ok', '2026-07-20T16:56:57.691Z');
